import java.io.*;

public class SecureCommandExecutionExample {

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter the name of the file to display: ");
        String fileName = br.readLine();

        // Validate input to ensure it contains only allowed characters (e.g., alphanumeric and certain special characters)
        if (!fileName.matches("[a-zA-Z0-9._-]+")) {
            System.out.println("Invalid file name input. Please provide a valid file name.");
            return;
        }

        // Construct the command with proper validation and escaping
        String[] command = {"sh", "-c", "cat " + fileName};

        Process process = Runtime.getRuntime().exec(command);
        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));

        String line;
        while ((line = reader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

